fn solve(n: i64, edges: Vec<Vec<i64>>, label: String) -> i64 {
    use std::collections::{HashSet, HashMap};
    use std::cmp::max;

    let n = n as usize;
    let mut graph = vec![HashSet::new(); n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        graph[u].insert(v);
        graph[v].insert(u);
    }

    let mut memo = HashMap::new();
    let mut max_len = 0;

    fn dfs(graph: &Vec<HashSet<usize>>, label: &String, visited: &mut HashSet<usize>, path: &mut Vec<char>, max_len: &mut i64, memo: &mut HashMap<String, i64>) {
        let mut key = String::new();
        for &v in visited.iter() {
            key.push_str(&label[v..v+1]);
        }
        if let Some(&len) = memo.get(&key) {
            *max_len = max(*max_len, len);
            return;
        }

        if path.len() > *max_len {
            *max_len = path.len() as i64;
        }

        let mut new_visited = visited.clone();
        let mut new_path = path.clone();

        let mut nodes = Vec::new();
        for i in 0..graph.len() {
            if !visited.contains(&i) {
                nodes.push(i);
            }
        }

        for &node in &nodes {
            if visited.contains(&node) {
                continue;
            }
            visited.insert(node);
            new_path.push(label[node]);
            let mut neighbors = graph[node].clone();
            for &neighbor in &neighbors {
                if !visited.contains(&neighbor) {
                    let mut new_visited = visited.clone();
                    new_visited.insert(neighbor);
                    let mut new_path = new_path.clone();
                    new_path.push(label[neighbor]);
                    dfs(graph, label, &mut new_visited, &mut new_path, max_len, memo);
                }
            }
            visited.remove(&node);
            new_path.pop();
        }

        let mut key = String::new();
        for &v in visited.iter() {
            key.push_str(&label[v..v+1]);
        }
        memo.insert(key, *max_len);
    }

    let mut visited = HashSet::new();
    let mut path = Vec::new();
    dfs(&graph, &label, &mut visited, &mut path, &mut max_len, &mut memo);

    max_len
}
