        let v = edge[1] as usize;
        graph[u].push(v);
        graph[v].push(u);
    }

    let mut max_len = 1; // At least one node can form a palindrome of length 1

    // Use BFS to explore all possible paths
    for start in 0..n {
        let mut visited = vec![false; n];
        visited[start] = true;
        let mut queue = vec![(start, vec![start])];

        while let Some((current, path)) = queue.pop() {
            // Check if the current path forms a palindrome
            let mut is_palindrome = true;
            for i in 0..path.len() / 2 {
                if label[path[i]] != label[path[path.len() - 1 - i]] {
                    is_palindrome = false;
                    break;
                }
            }
            if is_palindrome {
                max_len = max_len.max(path.len() as i64);
            }

            // Explore neighbors
            for &neighbor in &graph[current] {
                if !visited[neighbor] {
                    let mut new_visited = visited.clone();
                    new_visited[neighbor] = true;
                    let mut new_path = path.clone();
                    new_path.push(neighbor);
                    queue.push((neighbor, new_path));
                }
            }
        }
    }

    max_len
